var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"갈대 때문에 앞이 잘 안 보이네. 얼마나 걸어온 거지?","JPN":"茂みのせいで前がよく見えない。どれくらい歩いたんだろう？","ENG":"The weeds are blocking my view. Are we there yet?","TWN":"蘆葦擋著我的視線，我們是走多遠啦？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이상하군요.","JPN":"おかしいですね。","ENG":"This is weird.","TWN":"奇怪。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"분명 봉인에 가까워지고 있는데도, 침식체가 전혀 보이지 않습니다.","JPN":"間違いなく封印に近づいているのに、侵食体がまったく見当たりません。","ENG":"We’re definitely closer to the seal, but I don’t see any C.O.s.","TWN":"明明很靠近封印，卻完全沒看到侵蝕體。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"침식체도 여기가 위험하다는 걸 알고 들어오지 않는 게 아닐까?","JPN":"侵食体もここが危険だってことを察知して入ってこなかったんじゃない？","ENG":"Maybe the C.O.s also know that this is a dangerous place.","TWN":"會不會是侵蝕體也知道這裡很危險，所以才不進來？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그런 엉터리 같은……","JPN":"そんなデタラメな……","ENG":"That’s ridiculous...","TWN":"胡扯……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"음?!","JPN":"むっ！？","ENG":"Huh?","TWN":"嗯？！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공! 제 뒤로!","JPN":"奈由香殿！　私の後ろへ！","ENG":"Mr. Nayuka! Stay back!","TWN":"南裕夏！躲我後面！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"고, 고마워. 치후유.","JPN":"あ、ありがとう。千冬。","ENG":"Th-thank you, Chifuyu.","TWN":"謝…謝謝你，千冬。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그런데 방금 뭐가 날아왔는지 봤어?","JPN":"いま何が飛んで来たんだ？","ENG":"Did you see what it was?","TWN":"你有看到是什麼東西飛過來嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……비도였습니다.","JPN":"……苦無でした。","ENG":"It was a throwing knife.","TWN":"……是飛刀。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"비도? 칼 말이야?","JPN":"苦無？　ナイフのこと？","ENG":"A knife?","TWN":"飛刀？是刀嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"네. 적은 기척을 숨기고 있습니다. 침식체는 아니로군요.","JPN":"はい。敵は気配を消しています。侵食体ではありませんね。","ENG":"Yes. The enemy is hiding themselves. It’s not a C.O.","TWN":"是的。敵人在暗，我們在明，不過不是侵蝕體。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"침식체가 아니라면…… 사람이란 건가?","JPN":"侵食体じゃないなら……人ってこと？","ENG":"Then... it’s a human?","TWN":"不是侵蝕體的話…… 是人嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저도 그렇게 생각하고 싶진 않습니다만……","JPN":"そう思いたくはありませんが……","ENG":"I hope I’m wrong, but...","TWN":"我也不希望是，但是……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"과거, 이 영지에서 많은 연합원들이 오로치에게 희생됐습니다.","JPN":"過去、この領地では大勢の連合員がオロチの犠牲になりました。","ENG":"Many Alliance members lost their lives here in the hands of Orochi.","TWN":"以前在這個領地上，有很多聯盟成員因大蛇而犧牲。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"고심도 이면세계나 다름없는 이곳에 그들의 그림자가 배회하고 있다고 해도, 이상하지 않겠지요.","JPN":"高深度の裏世界ともいえるここに\\n彼らのシャドウが徘徊しているとしても、不思議ではありません。","ENG":"Since this place is not much different from the hyperdepths of the Counterside, I wouldn’t be surprised to see their Shadows wandering around.","TWN":"在這個如同是高深度異界的地方，就算有他們的暗影徘徊也並不意外。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"잠깐! 치후유!","JPN":"千冬、ちょっと待って！","ENG":"Wait, Chifuyu!","TWN":"等等！千冬！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저기 봐. 달빛에 뭔가 빛나고 있어.","JPN":"あそこ、月明かりで何かが光ってる。","ENG":"Look over there. Something’s glistening under the moonlight.","TWN":"看那邊，月光裡有什麼東西在發光。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저건…… 실?","JPN":"あれは……糸？","ENG":"Is that... a thread?","TWN":"那是…… 線?"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"거기냐!","JPN":"そこか！","ENG":"There you are!","TWN":"那邊！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……이런. 놓쳤나.","JPN":"……逃がしたか。","ENG":"... I missed.","TWN":"……可惡，沒抓到。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L32_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"어……? 저 가면은……?","JPN":"あれ……？　あのお面は……？","ENG":"Oh, that mask...","TWN":"呃……？這個面具是……？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"졸자가 알기를 이 일대는 혈기왕성한 젊은이들이 함부로 접근할 곳이 아닙니다만.","JPN":"ここは若者が容易く足を踏み入れて良い場所ではありませぬ。","ENG":"I do not believe that this is the right place for high-spirited youngsters.","TWN":"據我所知，這一帶應該不是血氣方剛的年輕人可以靠近的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"혹여 남녀께서는 남몰래 만리장성이라도 쌓으러 오셨는지요?","JPN":"よもや逢瀬のために……？","ENG":"Could it be that this merry young couple seeks a love nest?","TWN":"敢問二位是來這邊談情說愛的嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저, 저기, 뭔가 오해가 있는 것 같네요. 저흰 그런 이유로 온 게 아니라……","JPN":"あ、あの……何か誤解してるみたいです。\\n僕たちはそんなつもりでここを訪れたわけじゃ……","ENG":"I-I think you misunderstood. We’re not here to—","TWN":"那…那個，好像有點誤會。我們不是因爲那個原因來的……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"대답할 필요 없습니다, 나유카 공.","JPN":"答える必要はありません、奈由香殿。","ENG":"You don’t have to answer her, Mr. Nayuka.","TWN":"不用解釋，南裕夏。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저건 이미 산 사람이 아니니까요.","JPN":"あれはもう生者ではありませんから。","ENG":"She’s not a living person.","TWN":"她不是活人。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응? 산 사람이…… 아니라고?","JPN":"えっ？　生きて……ない？","ENG":"She’s... not a living person?","TWN":"嗯？不是……活人？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"후훗, 그렇지요.","JPN":"ふふっ、左様。","ENG":"Hah hah, right ye are.","TWN":"呵呵，沒錯。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"저는 죽어 있는 몸이라 두 분의 애틋한 감정을 이해하진 못한답니다.","JPN":"私は死者である故、お二人の気持ちを理解することはできませぬ。","ENG":"I am indeed an empty shell, and do not understand the passion that ye may carry.","TWN":"因爲我已是死去之軀，所以無法理解二位的男女之情。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"하지만, 두 분이 이곳에 머물러선 안 된다는 건 알고 있지요.","JPN":"しかし、お二人がここに留まっていてはいけないことはわかります。","ENG":"But I do know that ye art not supposed to be here.","TWN":"不過我知道的是，二位不能待在這裡。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그러니, 제가 이리 청할 때 돌아가 주시어요.","JPN":"どうか、すぐにここからお引き取りを。","ENG":"So please leave, while I’m asking ye nicely.","TWN":"所以，趁我還好好說話時請回吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"자신이 죽은 이유를 잊어버린 채 이승을 떠도는 사념이구나.","JPN":"自分が死んだ理由を忘れ、この世を彷徨う邪念か。","ENG":"You are a lingering will that forgot how you died.","TWN":"忘記自己死掉的原因，還在人世間遊蕩的思念嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"어떤 사정이 있어 이곳을 지키는지는 모르겠지만…….","JPN":"どのような事情でここを守っているのかはわからないが……","ENG":"I don’t know why you’re guarding this place...","TWN":"雖然不清楚你為何要守在這裡……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"길을 가로막겠다면, 그저 벨 뿐이다.","JPN":"我々の行く手を阻むのなら、ただ斬るのみ。","ENG":"But I will cut you down if you get into my way.","TWN":"但擋路者死。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L4_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"어리석으시군요.","JPN":"実に愚かですね。","ENG":"Foolish ye are.","TWN":"太愚蠢了。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"이곳을 넘어간다 하여 변하는 것은 없습니다.","JPN":"ここを越えたとしても何も変わりませぬ。","ENG":"Even if ye get past me, ye will not change a thing.","TWN":"就算越過這裡也不會有任何改變。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"밤중의 밀회도, 야반도주도 좋지만…….","JPN":"夜の逢瀬でも、夜逃げでも構いませぬが……","ENG":"A secret love affair and a moonlight flitting... They are all fine.","TWN":"不管你們是偷情或是私奔都好…"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그런 치기 어린 행동으로 명을 앞당기지는 마셔야지요.","JPN":"軽率な行動で命を縮めるのはおやめください。","ENG":"But such rash actions can shorten your lives.","TWN":"都不應該用這種幼稚的行為，來提前結束自己的性命吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL"}]`);export{e as default};